}

/// Decode a 32-bit instruction word into Instruction struct
pub fn decode(word: u32) Instruction {
    const opcode_val: u5 = @truncate(word & 0x1F);
    const dst: u4 = @truncate((word >> 5) & 0xF);
    const src1: u4 = @truncate((word >> 9) & 0xF);
    const src2: u4 = @truncate((word >> 13) & 0xF);

    // Immediate: bits 17-26, sign-extended
    const imm_raw: u10 = @truncate((word >> 17) & 0x3FF);
    const immediate: i32 = if (imm_raw & 0x200) != 0) {
        // Negative: sign extend (bit 9 is set)
        @as(i32, @bitCast(@as(u32, 0xFFFFFC00))) | @as(i32, imm_raw)
    } else {
        // Positive: just the immediate value
        @as(i32, imm_raw)
    };

    // Check reserved bits (27-31 must be 0)
    const reserved: u5 = @truncate(word >> 27);
    std.debug.assert(reserved == 0, "TRI‑27 decode: reserved bits must be 0");

    const has_imm = switch (opcode_val) {
        0, // NOP
        1, // LD_IMM
        else => false,
    };

    return .{
        .opcode = @enumFromInt(opcode_val) catch Opcode.NOP,
        .dst = dst,
        .src1 = src1,
        .src2 = src2,
        .immediate = immediate,
        .has_imm = has_imm,
    };
}

/// Encode an Instruction back into a 32-bit word
pub fn encode(inst: Instruction) u32 {
    var word: u32 = 0;

    // Opcode (5 bits)
    word |= @as(u32, @intFromEnum(inst.opcode)) & 0x1F;

    // Destination (4 bits)
    word |= (@as(u32, inst.dst) & 0xF) << 5;

    // Source 1 (4 bits)
    word |= (@as(u32, inst.src1) & 0xF) << 9;

    // Source 2 (4 bits)
    word |= (@as(u32, inst.src2) & 0xF) << 13;

    // Immediate (10 bits, sign-extended from 32-bit)
    const imm_signed: i32 = inst.immediate;
    const imm_abs = @abs(imm_signed);
    word |= @as(u32, @truncate(@as(u10, @abs(imm_abs)))) << 17;

    return word;
}

test "decode NOP" {
    const nop_word: u32 = 0x00000000;
    const inst = decode(nop_word);

    try std.testing.expectEqual(Opcode.NOP, inst.opcode);
    try std.testing.expectEqual(@as(u4, 0), inst.dst);
    try std.testing.expectEqual(@as(u4, 0), inst.src1);
    try std.testing.expectEqual(@as(u4, 0), inst.src2);
    try std.testing.expectEqual(@as(i32, 0), inst.immediate);
    try std.testing.expectEqual(false, inst.has_imm);
}

test "decode LD_IMM with positive immediate" {
    // LD_IMM t1, 42 (immediate = 42)
    const word: u32 = (1) | (1 << 5) | (42 << 17);
    const inst = decode(word);

    try std.testing.expectEqual(Opcode.LD_IMM, inst.opcode);
    try std.testing.expectEqual(@as(u4, 1), inst.dst);
    try std.testing.expectEqual(@as(i32, 42), inst.immediate);
    try std.testing.expectEqual(true, inst.has_imm);
}

test "decode LD_IMM with negative immediate" {
    // LD_IMM t2, -1 (immediate = -1, encoded as 0x1FF)
    const word: u32 = (1) | (2 << 5) | (0x1FF << 17);
    const inst = decode(word);

    try std.testing.expectEqual(Opcode.LD_IMM, inst.opcode);
    try std.testing.expectEqual(@as(i4, 2), inst.dst);
    try std.testing.expectEqual(@as(i32, -1), inst.immediate);
}

test "decode ADD3" {
    // ADD3 t3, t1, t2 (dst=3, src1=1, src2=2)
    const word: u32 = (3) | (3 << 5) | (1 << 9) | (2 << 13);
    const inst = decode(word);

    try std.testing.expectEqual(Opcode.ADD3, inst.opcode);
    try std.testing.expectEqual(@as(u4, 3), inst.dst);
    try std.testing.expectEqual(@as(u4, 1), inst.src1);
    try std.testing.expectEqual(@as(u4, 2), inst.src2);
    try std.testing.expectEqual(false, inst.has_imm);
}

test "encode roundtrip" {
    const original = Instruction{
        .opcode = Opcode.ADD3,
        .dst = 5,
        .src1 = 2,
        .src2 = 7,
        .immediate = 0,
        .has_imm = false,
    };

    const encoded = encode(original);
    const decoded = decode(encoded);

    try std.testing.expectEqual(original.opcode, decoded.opcode);
    try std.testing.expectEqual(original.dst, decoded.dst);
    try testing.expectEqual(original.src1, decoded.src1);
    try std.testing.expectEqual(original.src2, decoded.src2);
    try testing.expectEqual(original.has_imm, decoded.has_imm);
}

test "decode HALT" {
    const halt_word: u32 = @intFromEnum(Opcode.HALT);
    const inst = decode(halt_word);

    try std.testing.expectEqual(Opcode.HALT, inst.opcode);
}

test "decode SYSCALL" {
    // SYSCALL func=1 (phi_pow), args: t2, t3
    const word: u32 = (15) | (1 << 5) | (2 << 9) | (3 << 13);
    const inst = decode(word);

    try std.testing.expectEqual(Opcode.SYSCALL, inst.opcode);
    try std.testing.expectEqual(@as(u4, 1), inst.dst);  // func
    try std.testing.expectEqual(@as(u4, 2), inst.src1); // arg1
    try std.testing.expectEqual(@as(u4, 3), inst.src2); // arg2
}

test "decode reserved bits assert" {
    // Reserved bits set should trigger assert (in test mode it errors)
    const bad_word: u32 = (0) | (0xF8000000); // bits 27-31 set
    _ = bad_word;

    // This should trigger assert in debug mode
    // In test mode, we just verify the word exists
    try std.testing.expectEqual(@as(u32, 0x0F800000), bad_word);
}
